#!/usr/bin/env python3 """Local sovereign token rollup + hypothetical cloud savings vs paid baselines.""" from __future__ import annotations import json import sqlite3 import time from datetime import datetime, timezone from pathlib import Path from typing import Any, Dict, Iterable, List, Optional, Tuple HERMES_ROOT = Path(r"D:\HermesData") STATE_DB = HERMES_ROOT / "state.db" TOTALS_PATH = Path(r"D:\PhronesisVault\Operations\logs\sovereign-usage-totals.json") PROVENANCE_LOG = Path(r"D:\PhronesisVault\Operations\logs\generation-provenance-trace.jsonl") TOKEN_USAGE_LOG = Path(r"D:\PhronesisVault\Operations\token-usage-local.jsonl") LOCAL_BACKENDS = frozenset( {"native_8090", "native_8090_cached", "vault_v0.11", "ollama"} ) LOCAL_BILLING_PROVIDERS = frozenset({"custom:phronesis-sovereign", "custom", "local"}) LOCAL_BILLING_URL_MARKERS = ("127.0.0.1:8091", "127.0.0.1:8090", "localhost:8091", "localhost:8090") # USD per 1M tokens official docs snapshots (2026-07). CLOUD_BASELINES: Dict[str, Dict[str, Any]] = { "grok-4.20": { "label": "Grok 4.20", "input_per_m": 1.25, "output_per_m": 2.50, "source": "https://docs.x.ai/developers/pricing", "default": True, }, "claude-sonnet-4-6": { "label": "Claude Sonnet 4.6", "input_per_m": 3.00, "output_per_m": 15.00, "source": "anthropic-pricing-2026", }, "gpt-4o": { "label": "GPT-4o", "input_per_m": 5.00, "output_per_m": 15.00, "source": "openai-pricing-snapshot", }, } DEFAULT_BASELINE_ID = "grok-4.20" PROVENANCE_INPUT_ESTIMATE = 2000 def _utc_now() -> str: return datetime.now(timezone.utc).isoformat() def _day_key(ts: Optional[float] = None) -> str: when = datetime.fromtimestamp(ts or time.time(), tz=timezone.utc) return when.strftime("%Y-%m-%d") def _parse_iso_ts(value: Any) -> Optional[float]: if not value: return None try: return datetime.fromisoformat(str(value).replace("Z", "+00:00")).timestamp() except (TypeError, ValueError): return None def _load_json(path: Path) -> Dict[str, Any]: if not path.is_file(): return {} try: data = json.loads(path.read_text(encoding="utf-8-sig")) return data if isinstance(data, dict) else {} except Exception: return {} def _atomic_write_json(path: Path, payload: Dict[str, Any]) -> None: path.parent.mkdir(parents=True, exist_ok=True) tmp = path.with_suffix(path.suffix + ".tmp") tmp.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8") tmp.replace(path) def _empty_bucket() -> Dict[str, int]: return {"input_tokens": 0, "output_tokens": 0, "requests": 0} def _add_bucket(target: Dict[str, int], inp: int, out: int, requests: int = 1) -> None: target["input_tokens"] = int(target.get("input_tokens", 0)) + max(0, inp) target["output_tokens"] = int(target.get("output_tokens", 0)) + max(0, out) target["requests"] = int(target.get("requests", 0)) + max(0, requests) def is_local_billing_row(row: Dict[str, Any]) -> bool: provider = str(row.get("billing_provider") or "").strip().lower() base_url = str(row.get("billing_base_url") or "").strip().lower() if provider in LOCAL_BILLING_PROVIDERS: return True return any(marker in base_url for marker in LOCAL_BILLING_URL_MARKERS) def estimate_cost_usd( input_tokens: int, output_tokens: int, baseline_id: str = DEFAULT_BASELINE_ID, ) -> float: baseline = CLOUD_BASELINES.get(baseline_id) or CLOUD_BASELINES[DEFAULT_BASELINE_ID] inp_cost = (max(0, input_tokens) / 1_000_000) * float(baseline["input_per_m"]) out_cost = (max(0, output_tokens) / 1_000_000) * float(baseline["output_per_m"]) return round(inp_cost + out_cost, 4) def _baseline_payload() -> List[Dict[str, Any]]: rows: List[Dict[str, Any]] = [] for baseline_id, meta in CLOUD_BASELINES.items(): rows.append( { "id": baseline_id, "label": meta["label"], "input_per_m": meta["input_per_m"], "output_per_m": meta["output_per_m"], "source": meta.get("source"), "default": bool(meta.get("default")), } ) return rows def load_totals() -> Dict[str, Any]: data = _load_json(TOTALS_PATH) if not data: data = { "version": 1, "updated_at": _utc_now(), "lifetime": _empty_bucket(), "daily": {}, "backfill": None, } data.setdefault("lifetime", _empty_bucket()) data.setdefault("daily", {}) return data def record_local_usage( *, input_tokens: int, output_tokens: int, backend: str = "native_8090", model: Optional[str] = None, source: str = "proxy", timestamp: Optional[float] = None, ) -> None: """Increment rolling local token totals (proxy / bridge call sites).""" if input_tokens <= 0 and output_tokens <= 0: return when = timestamp or time.time() day = _day_key(when) totals = load_totals() _add_bucket(totals["lifetime"], input_tokens, output_tokens) daily = totals["daily"].setdefault(day, _empty_bucket()) _add_bucket(daily, input_tokens, output_tokens) totals["updated_at"] = _utc_now() totals["last_event"] = { "at": datetime.fromtimestamp(when, tz=timezone.utc).isoformat(), "backend": backend, "model": model, "source": source, "input_tokens": input_tokens, "output_tokens": output_tokens, } _atomic_write_json(TOTALS_PATH, totals) def _extract_usage_from_event(event: Dict[str, Any]) -> Tuple[int, int]: usage = event.get("usage") if isinstance(usage, dict): inp = int(usage.get("prompt_tokens") or usage.get("input_tokens") or 0) out = int(usage.get("completion_tokens") or usage.get("output_tokens") or 0) if inp or out: return inp, out inp = int(event.get("prompt_tokens") or event.get("input_tokens") or 0) out = int(event.get("completion_tokens") or event.get("output_tokens") or 0) if inp or out: return inp, out preview = str(event.get("response_preview") or event.get("task_preview") or "") out_est = max(50, len(preview) // 4) if preview else 0 inp_est = int(event.get("prompt_tokens_estimate") or PROVENANCE_INPUT_ESTIMATE) return inp_est, out_est def _aggregate_jsonl( path: Path, *, cutoff_ts: float, predicate, ) -> Dict[str, Any]: lifetime = _empty_bucket() daily: Dict[str, Dict[str, int]] = {} if not path.is_file(): return {"lifetime": lifetime, "daily": daily, "source": str(path)} for line in path.read_text(encoding="utf-8", errors="replace").splitlines(): if not line.strip(): continue try: event = json.loads(line) except json.JSONDecodeError: continue if not predicate(event): continue ts = _parse_iso_ts(event.get("timestamp")) if ts is not None and ts < cutoff_ts: continue inp, out = _extract_usage_from_event(event) if not inp and not out: continue _add_bucket(lifetime, inp, out) if ts is not None: day = _day_key(ts) bucket = daily.setdefault(day, _empty_bucket()) _add_bucket(bucket, inp, out) return {"lifetime": lifetime, "daily": daily, "source": str(path)} def _query_state_db_local(cutoff_ts: float) -> Dict[str, Any]: lifetime = _empty_bucket() daily: Dict[str, Dict[str, int]] = {} cloud_paid = _empty_bucket() if not STATE_DB.is_file(): return { "lifetime": lifetime, "daily": daily, "cloud_paid": cloud_paid, "source": str(STATE_DB), "available": False, } uri = f"file:{STATE_DB.as_posix()}?mode=ro" try: conn = sqlite3.connect(uri, uri=True, timeout=3) conn.row_factory = sqlite3.Row rows = conn.execute( """ SELECT date(started_at, 'unixepoch') AS day, input_tokens, output_tokens, cache_read_tokens, estimated_cost_usd, billing_provider, billing_base_url, model FROM sessions WHERE started_at > ? """, (cutoff_ts,), ).fetchall() conn.close() except Exception as exc: return { "lifetime": lifetime, "daily": daily, "cloud_paid": cloud_paid, "source": str(STATE_DB), "available": False, "error": str(exc), } for row in rows: rowd = dict(row) inp = int(rowd.get("input_tokens") or 0) out = int(rowd.get("output_tokens") or 0) if inp <= 0 and out <= 0: continue day = str(rowd.get("day") or _day_key()) if is_local_billing_row(rowd): _add_bucket(lifetime, inp, out) bucket = daily.setdefault(day, _empty_bucket()) _add_bucket(bucket, inp, out) else: _add_bucket(cloud_paid, inp, out) return { "lifetime": lifetime, "daily": daily, "cloud_paid": cloud_paid, "source": str(STATE_DB), "available": True, } def _merge_buckets(target: Dict[str, int], extra: Dict[str, int]) -> None: _add_bucket( target, int(extra.get("input_tokens") or 0), int(extra.get("output_tokens") or 0), int(extra.get("requests") or 0), ) def _merge_daily( target: Dict[str, Dict[str, int]], extra: Dict[str, Dict[str, int]], ) -> None: for day, bucket in (extra or {}).items(): merged = target.setdefault(day, _empty_bucket()) _merge_buckets(merged, bucket) def ensure_provenance_backfill() -> None: """One-time seed totals from generation provenance when totals file is empty.""" totals = load_totals() lifetime = totals.get("lifetime") or _empty_bucket() if int(lifetime.get("requests") or 0) > 0: return if totals.get("backfill"): return agg = _aggregate_jsonl( PROVENANCE_LOG, cutoff_ts=0.0, predicate=lambda e: ( e.get("event") == "proxy_dispatch_ok" and str(e.get("backend") or "") in LOCAL_BACKENDS ), ) if int(agg["lifetime"].get("requests") or 0) <= 0: return totals["lifetime"] = agg["lifetime"] totals["daily"] = agg["daily"] totals["backfill"] = { "source": "generation-provenance-trace.jsonl", "at": _utc_now(), "note": "Estimated input tokens where upstream usage was not logged.", } totals["updated_at"] = _utc_now() _atomic_write_json(TOTALS_PATH, totals) def _cutoff_day_str(period_days: int) -> str: cutoff_ts = time.time() - max(1, period_days) * 86400 return _day_key(cutoff_ts) def build_usage_savings(*, period_days: int = 30) -> Dict[str, Any]: """Panel-ready local usage + cloud savings snapshot.""" ensure_provenance_backfill() cutoff_ts = time.time() - max(1, period_days) * 86400 cutoff_day = _cutoff_day_str(period_days) totals = load_totals() totals_daily = totals.get("daily") or {} state_db = _query_state_db_local(cutoff_ts) period = _empty_bucket() for day, bucket in totals_daily.items(): if day >= cutoff_day: _merge_buckets(period, bucket) provenance: Dict[str, Any] = {"lifetime": _empty_bucket(), "daily": {}, "source": str(PROVENANCE_LOG)} if int(period.get("requests") or 0) <= 0: provenance = _aggregate_jsonl( PROVENANCE_LOG, cutoff_ts=cutoff_ts, predicate=lambda e: ( e.get("event") == "proxy_dispatch_ok" and str(e.get("backend") or "") in LOCAL_BACKENDS ), ) period = provenance["lifetime"] if int(period.get("requests") or 0) <= 0: bridge_log = _aggregate_jsonl( TOKEN_USAGE_LOG, cutoff_ts=cutoff_ts, predicate=lambda e: str(e.get("choice") or "") == "local", ) if int(bridge_log["lifetime"].get("requests") or 0) > 0: period = bridge_log["lifetime"] else: bridge_log = {"lifetime": _empty_bucket(), "source": str(TOKEN_USAGE_LOG)} if int(period.get("requests") or 0) <= 0 and state_db.get("available"): period = state_db["lifetime"] input_tokens = int(period.get("input_tokens") or 0) output_tokens = int(period.get("output_tokens") or 0) total_tokens = input_tokens + output_tokens requests = int(period.get("requests") or 0) savings_by_baseline: Dict[str, Any] = {} for baseline_id in CLOUD_BASELINES: hypothetical = estimate_cost_usd(input_tokens, output_tokens, baseline_id) savings_by_baseline[baseline_id] = { "hypothetical_usd": hypothetical, "saved_usd": hypothetical, "local_actual_usd": 0.0, } default_saved = savings_by_baseline[DEFAULT_BASELINE_ID]["saved_usd"] cloud_paid = state_db.get("cloud_paid") or _empty_bucket() return { "period_days": period_days, "updated_at": _utc_now(), "local": { "input_tokens": input_tokens, "output_tokens": output_tokens, "total_tokens": total_tokens, "requests": requests, "actual_cost_usd": 0.0, "note": "Local llama inference API cost is $0; electricity not included.", }, "cloud_comparison": { "default_baseline_id": DEFAULT_BASELINE_ID, "baselines": _baseline_payload(), "saved_usd": default_saved, "saved_usd_by_baseline": savings_by_baseline, "headline": ( f"~${default_saved:,.2f} saved vs {CLOUD_BASELINES[DEFAULT_BASELINE_ID]['label']} " f"over {period_days}d" if default_saved > 0 else f"Tracking local tokens savings appear once sovereign dispatches accumulate" ), }, "cloud_paid_period": { "input_tokens": int(cloud_paid.get("input_tokens") or 0), "output_tokens": int(cloud_paid.get("output_tokens") or 0), "note": "Non-local sessions in state.db (Grok, fleet, etc.) for contrast.", }, "sources": { "totals_file": str(TOTALS_PATH), "totals_updated_at": totals.get("updated_at"), "provenance_log": provenance.get("source"), "bridge_log": str(TOKEN_USAGE_LOG), "state_db": { "path": state_db.get("source"), "available": state_db.get("available", False), "error": state_db.get("error"), }, "backfill": totals.get("backfill"), }, } def usage_from_openai_response(response: Optional[Dict[str, Any]]) -> Tuple[int, int]: if not isinstance(response, dict): return 0, 0 usage = response.get("usage") if not isinstance(usage, dict): return 0, 0 inp = int(usage.get("prompt_tokens") or usage.get("input_tokens") or 0) out = int(usage.get("completion_tokens") or usage.get("output_tokens") or 0) return inp, out if __name__ == "__main__": print(json.dumps(build_usage_savings(), indent=2))